class ParkingStorage(context: Context) {

    private val prefs = context.getSharedPreferences(
        "parking_prefs", Context.MODE_PRIVATE
    )
    private val gson = Gson()

    fun save(spot: ParkingSpot) {
        val json = gson.toJson(spot)           // object → JSON string
        prefs.edit().putString("current_spot", json).apply()
    }

    fun load(): ParkingSpot? {
        val json = prefs.getString("current_spot", null)
            ?: return null                     // nothing saved yet
        return gson.fromJson(json, ParkingSpot::class.java)
    }

    fun clear() {
        prefs.edit().remove("current_spot").apply()
    }
}

