class LocationHelper(private val context: Context) {

    private val fusedClient =
        LocationServices.getFusedLocationProviderClient(context)

    fun getCurrentLocation(onResult: (lat: Double, lng: Double) -> Unit) {
        if (ContextCompat.checkSelfPermission(
                context, Manifest.permission.ACCESS_FINE_LOCATION
            ) != PackageManager.PERMISSION_GRANTED
        ) {
            onResult(0.0, 0.0)   // permission not granted — caller should handle
            return
        }

        fusedClient.lastLocation
            .addOnSuccessListener { location ->
                location?.let {
                    onResult(it.latitude, it.longitude)
                } ?: onResult(0.0, 0.0)   // null = no cached fix yet
            }
            .addOnFailureListener {
                onResult(0.0, 0.0)        // GPS service unavailable
            }
    }
}

