        }

        Spacer(Modifier.weight(1f))
        OutlinedButton(onClick = onBack, modifier = Modifier.fillMaxWidth()) {
            Text("Back", color = Color.White)
        }
    }
}

class NotificationHelper(private val context: Context) {

    private val notificationManager =
        NotificationManagerCompat.from(context)

    init {
        // Create channel once — safe to call repeatedly, Android ignores duplicates
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                "parking_channel",
                "Parking Reminders",
                NotificationManager.IMPORTANCE_DEFAULT
            )
            notificationManager.createNotificationChannel(channel)
        }
    }

    fun showParkingNotification(timeParked: String) {
        // Android 13+: check POST_NOTIFICATIONS permission
        if (Build.VERSION.SDK_INT >= 33 &&
            ContextCompat.checkSelfPermission(
                context, Manifest.permission.POST_NOTIFICATIONS
            ) != PackageManager.PERMISSION_GRANTED
        ) return

        val intent = Intent(context, MainActivity::class.java)
        val pendingIntent = PendingIntent.getActivity(
            context, 0, intent,
            PendingIntent.FLAG_IMMUTABLE
        )

        val notification = NotificationCompat.Builder(context, "parking_channel")
            .setSmallIcon(android.R.drawable.ic_dialog_map)
            .setContentTitle("Bike parked!")
            .setContentText("You parked at $timeParked — tap to find it")
            .setContentIntent(pendingIntent)
            .setAutoCancel(true)
            .build()

        notificationManager.notify(1001, notification)
    }
}

